export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "03:05。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門後面的聲音停了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是突然停。是慢慢變少。腳步聲先少。然後器械碰撞的聲音少了。然後低語少了。最後什麼都沒了。像一條河退潮。退到只剩地板縫裡的水痕。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門開了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫護走出來。一個。兩個。第三個把口罩拉到下巴上。他們走得很慢。不是累的那種慢。是做完一件事情之後、還沒決定下一步的那種慢。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "跟在後面的是兩個人。一個穿警察制服。一個穿站務人員的反光背心。他們和醫護在走廊中段停下來。站得很近。聲音壓得很低。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在牆邊。她沒有走過去。她不需要走過去。她看得見他們的臉。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫護的臉。不是驚慌。不是悲傷。是一種很平的、很乾的東西。像做完一件沒有成功的事。像把一個沒救回來的結果收進格式裡。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見其中一個詞。從那三個人之間漏出來。只有兩個音節。壓在喉嚨底部。但走廊太安靜了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "死亡確認。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有動。她的背還靠在牆上。手還在口袋裡。眼睛睜著。看著走廊中段那三個人。他們沒有看她。沒有人看她。她不是家屬。沒有人需要向她宣告任何事。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警察在講電話。聲音很低。她聽見幾個字。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "⋯⋯傷勢惡化。處置中急變。搬送後⋯⋯", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "後面的字被走廊的空氣吃掉了。但前面那幾個字她聽清楚了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯傷勢惡化。處置中急變。沒有明顯錯。千田確實重傷。他確實從施工通道被送進來。他確實在觀察區。任何人聽到這幾個字，都會點頭。都會覺得合理。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但順序不對。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把順序在腦子裡走了一遍。很慢。像在讀一張時間軸。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田在施工通道被攻擊。外殼疑似在病人物袋。病人物袋轉入醫院安全暫存。琴音知道醫院名。琴音知道有「東西」。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯病人物袋變成私物一式。病人物袋進入交通案件交接箱。千田急變。千田死亡。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯每一個環節都是正常的。每一個環節單獨拿出來都說得通。但排在一起——外殼先被處理。千田才急變。不是千田先惡化，再處理物品。是物品先離開他的身邊。然後他就死了。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從口袋裡摸出那張紙。攤開。翻到背面。背面已經寫滿了。她翻到正面。正面也快滿了。她找到一條空白的縫。用指甲壓。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯寫在一起。一頁。全部。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她壓得很慢。指甲在紙上留下淺淺的痕。一行一行。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯攻擊點。第一輪：不明，被誤認為第七車。第二輪：施工通道。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯死亡地點。第一輪：第七車。第二輪：醫院。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯外殼位置。第一輪：我手中，變成嫌疑畫面。第二輪：病人物袋。交通案件關聯物。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我的身份。第一輪：嫌疑人。第二輪：目擊者。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯官方版本。第一輪：車內持尖銳物。第二輪：傷勢惡化。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯琴音破綻。第一輪：21:19 已讀未回。第二輪：醫院名。東西。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那一頁。六行。兩欄。第一輪和第二輪。並排。像兩張同一個人的照片。表情不同。死法不同。但都死了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在表格下面壓了一行新的字。壓得很重。指甲幾乎把紙戳穿。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是怎麼救千田。是誰一定要他不能醒來。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。唸了一遍。沒有出聲。在腦子裡唸的。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯對。問題變了。第一輪我問的是「千田為什麼會死」。第二輪我問的是「為什麼他不能活著開口」。這不是同一個問題。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機在口袋裡震了一下。她掏出來。螢幕亮了。頂部跳出一條通知。不是琴音。是新聞推送。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "灣岸新交通深夜事件，搬送男性傷者急變。詳細確認中。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯傷者。不是「死者」。不是「不治」。是「傷者」。詳細確認中。媒體還沒拿到正式說法。醫院裡已經確認了。外面還沒有。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她關掉螢幕。又亮了。又一條。這次是琴音。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.ShiraishiKotone, character: "白石琴音", dialogue: "澪，拜託妳先離開那裡。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.ShiraishiKotone_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "九個字。沒有標點。沒有解釋。沒有「為什麼還在」。沒有「發生什麼事了」。只有一個指令。拜託。離開。那裡。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她知道我在醫院。我沒有告訴她我還在。她上次通話的時候，我說「我晚點回去」。她怎麼知道我還沒走。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯更不對的是語氣。不是「妳怎麼還在那裡」。是「拜託妳先離開」。像知道有什麼事剛剛發生。像知道醫院不再是安全的地方。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯或者只是擔心。只是朋友擔心。只是她在家裡睡不著，看到新聞推送，發現灣岸新交通那條事件還沒結束，叫我先走。可以這樣理解。可以。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回。她把手機關掉。塞回口袋。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不回。現在不能回。她知道太多。我還不知道她為什麼知道太多。但我不能再把任何東西交給她。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來。塞進內袋。她從牆邊站直。走廊中段那三個人已經散了。警察往急診出口走。站務人員往另一個方向。醫護回了觀察區。門又關上了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向出口。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "03:20。醫院大廳。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "自動門在她面前滑開。夜風灌進來。很涼。帶著一點海的味道。灣岸的方向。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走過大廳。腳步聲在空蕩蕩的磁磚地上很響。牆上有一張海報。不起眼。比急診告示板小很多。掛在出口旁邊的牆角。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她掃了一眼。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "海報上寫著「災害時青少年心理支援合作醫療網」。下面是一排合作機構的名稱。字很小。她沒有停下來看。但她的視線停在海報角落。那裡有一個標誌。很小。一條波浪線。像睡眠圖的波形。像腦電波的曲線。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯睡眠波形。悠真的睡眠研究說明單上也有類似的圖。那張說明單。在家裡。在他桌上。和他失蹤前最後幾天的東西放在一起。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有停下來。她繼續走。海報留在牆上。那個波形留在她的視網膜裡。一秒。然後被夜風吹散了。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "自動門在她身後關上。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "03:25。醫院外。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天還沒亮。路燈把她的影子拉得很長。灣岸方向的海面是一片黑。不是夜色的黑。是一種更深的、更厚的、像有重量的黑。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯黑色海。第一輪夢裡的那片海。悠真畫在筆記本上的那片海。一模一樣的顏色。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在路邊。風把頭髮吹到臉上。她沒有撥開。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想起千田。兩輪。兩次。他都拼命想留下一件事。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪，他把外殼塞給我。說「不要救東京」。第二輪，他抓空。像在找薄片。像在說「袋子」。兩輪都指向同一件事。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真的簡訊不是悠真打的。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是千田兩輪都沒有改變的線索。不是外殼。不是醫院名。不是施工通道。是這一句。悠真的簡訊不是悠真本人發的。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從內袋摸出那張紙。攤開。她看著自己寫下的字。不是表格。是散落在紙頁各處的詞。她用指甲把它們圈在一起。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯災害。交通。安全流程。睡眠研究。悠真。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五個詞。散在紙上。被她的指甲圈進同一個範圍裡。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田是災害警報系統的工程師。他死在交通系統的限制區。他的東西被歸進交通案件關聯物。醫院牆上有災害心理支援的海報。海報上有睡眠研究的波形。悠真在睡眠研究中心。悠真失蹤了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這些不是五件分開的事。是同一張網。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那五個詞。風把紙角吹得抖了一下。她用手指壓住。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田必須閉嘴。也許不是因為他知道誰刺了他。他重傷。他可能根本沒看清那個人的臉。但他知道另一件事。他知道悠真「為什麼」被帶走。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不是因為看見了凶手才被殺。是因為看見了原因。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來。塞回內袋。手指碰到小鏡子的布套。她沒有拿出來。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著灣岸方向的海。黑的。平的。沒有浪。像一面關著的鏡子。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯她救下了第七車裡的千田浩介。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但第二次，死亡比她早一步等在醫院。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯而下一個問題，不再是千田為什麼會死。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯是悠真究竟被選中了什麼。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。背對著海。朝回家的方向走。路燈一盞一盞在她前面亮著。又一盞一盞在她身後暗下去。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "天還沒亮。但她知道，天會亮的。天亮之後，她不再先查千田。她要回家。打開悠真的房間。把睡眠研究說明單、學校通知、遊戲帳號座標、小鏡子背面的刮痕、黑色海的塗鴉——全部放在同一張桌上。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她第一次把問題從「悠真在哪裡」改成「悠真為什麼被選中」。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "風從灣岸吹過來。很涼。帶著海的味道。黑色的海在她背後。很安靜。像在等她回頭。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回頭。", background: Background.Chapter_8_Ch8_Act7_S2 },
];
